const initialInvestment = inputs.initialInvestmentCost;
const annualMaintenance = inputs.annualMaintenanceCost;
const duration = inputs.projectDurationYears;
const baselineRevenue = inputs.baselineAnnualRevenue;
const revenueGrowthRate = inputs.expectedRevenueGrowthAI / 100;
const costSavingsRate = inputs.expectedCostSavingsAI / 100;
const baselineOperatingCosts = inputs.baselineAnnualOperatingCosts;
const discountRate = inputs.discountRate / 100;

// Input validation for duration
if (duration <= 0) {
    return {
        totalInvestmentCost: initialInvestment,
        totalBenefits: 0,
        netBenefit: -initialInvestment,
        roiPercentage: initialInvestment === 0 ? 0 : -100,
        paybackPeriod: 'N/A (Duration must be > 0)',
        npv: -initialInvestment
    };
}

let totalInvestmentOutlay = initialInvestment + (annualMaintenance * duration);
let totalBenefitsSum = 0;
let cashFlowsForNPV = []; // Represents (annual gross benefits - annual maintenance)

// Calculate annual benefits and cash flows for each year
for (let i = 1; i <= duration; i++) {
    const annualRevenueIncrease = baselineRevenue * revenueGrowthRate;
    const annualCostDecrease = baselineOperatingCosts * costSavingsRate;
    const annualGrossBenefit = annualRevenueIncrease + annualCostDecrease;
    totalBenefitsSum += annualGrossBenefit;

    const annualNetCashInflow = annualGrossBenefit - annualMaintenance;
    cashFlowsForNPV.push(annualNetCashInflow);
}

const netBenefit = totalBenefitsSum - totalInvestmentOutlay;

// ROI Calculation
const roiPercentage = totalInvestmentOutlay === 0
    ? (netBenefit >= 0 ? Infinity : -100) // If no investment and benefits, ROI is conceptually infinite. If no investment and loss, -100.
    : (netBenefit / totalInvestmentOutlay) * 100;

// Payback Period Calculation
let paybackPeriod = 'N/A';
let cumulativeCashFlow = -initialInvestment; // Start with the initial outflow
let periodReached = false;

if (initialInvestment === 0) {
    if (netBenefit >= 0) {
        paybackPeriod = '0.00'; // Immediate payback if no initial investment and non-negative benefits
    } else {
        paybackPeriod = '> 0.00'; // If no initial investment but negative benefits
    }
} else {
    for (let i = 0; i < duration; i++) {
        if (cashFlowsForNPV[i] === 0) {
             // If no cash flow in a year, skip or handle as no progress
             if (cumulativeCashFlow < 0) continue; // If still negative, no progress on payback
        }
        cumulativeCashFlow += cashFlowsForNPV[i];

        if (cumulativeCashFlow >= 0) {
            // Payback occurs during this year
            const previousCumulativeCashFlow = cumulativeCashFlow - cashFlowsForNPV[i];
            // Calculate the fraction of the year for payback
            paybackPeriod = (i + (-previousCumulativeCashFlow / cashFlowsForNPV[i])).toFixed(2);
            periodReached = true;
            break;
        }
    }
    if (!periodReached) {
        paybackPeriod = '> ' + duration.toFixed(0) + ' years';
    }
}

// NPV Calculation
let npv = -initialInvestment; // Start with the initial outlay
for (let i = 0; i < duration; i++) {
    npv += cashFlowsForNPV[i] / Math.pow(1 + discountRate, i + 1);
}

return {
    totalInvestmentCost: totalInvestmentOutlay,
    totalBenefits: totalBenefitsSum,
    netBenefit: netBenefit,
    roiPercentage: roiPercentage,
    paybackPeriod: paybackPeriod,
    npv: npv
};
